def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        base_multiplier = 1.0
        penalty_factor = 1.0
        bonus_factor = 1.0
        for j in range(1, 15):
            if j % 3 == 0 and j % 5 != 0:
                base_multiplier *= 1.05
            elif j % 5 == 0 and j % 3 != 0:
                base_multiplier *= 0.92
            elif j % 7 == 0:
                base_multiplier *= 1.1
            exp_component = np.exp(-ratio * (j ** 1.1))
            log_component = np.log1p(j * ratio)
            score_component = (j ** 2) * exp_component / (log_component + 1)
            if ratio < 0.1 * j:
                score += score_component * base_multiplier
            else:
                score += (np.sqrt(j) + ratio * j) * base_multiplier / (j + 2)
            if cap % (j + 3) == 0:
                penalty_factor *= 0.95
            elif (cap + j * 2) % 4 == 0:
                penalty_factor *= 1.04
            if j % 4 == 1 and cap > item * j:
                increment = 0
                for k in range(1, j // 2 + 1):
                    diff = cap - item * k
                    if diff > 0 and diff % 3 == 0:
                        increment += np.sin(diff / (k + 1)) * (k + 2)
                    else:
                        increment -= np.cos(abs(diff) / (k + 3)) * (k + 1)
                score += increment * 0.1
            if j == 14:
                for m in range(1, 6):
                    delta = cap - item * m
                    if delta == 0:
                        bonus_factor *= 1.2
                    elif delta > 0:
                        bonus_factor *= 1 + (np.tanh(delta / (m + 1)) * 0.1)
                    else:
                        bonus_factor *= 1 - (np.tanh(abs(delta) / (m + 1)) * 0.1)
        score *= bonus_factor * penalty_factor
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap + item) * penalty_factor
        else:
            if cap > item * 3:
                priorities[i] = -score / (np.cbrt(cap) + 1)
            else:
                priorities[i] = -score / (cap + item)
        if ratio > 0.85:
            priorities[i] *= 1.15
        elif ratio < 0.05:
            priorities[i] *= 0.75
        else:
            if cap % 2 == 0 and int(item) % 2 == 0:
                priorities[i] *= 1.05
            elif cap % 2 != 0 and int(item) % 2 != 0:
                priorities[i] *= 0.95
    return priorities
